legend_text{5} = strcat('$T_\mathrm{upd}=', num2str(T_x_vector(5)), ...
    '\times', num2str(T_y_vector(5)), '$');

% Last curve: T_upd = 12x12 (largest), solid diamond — highlighted
p6 = plot(prc95(:, length(T_vector)), '-d', ... %[output:37f1a114]
    'LineWidth', 2, 'MarkerSize', 8); %[output:37f1a114]
legend_text{6} = strcat('$T_\mathrm{upd}=', num2str(T_x_vector(length(T_vector))), ...
    '\times', num2str(T_y_vector(length(T_vector))), '$');

plot(30*ones(1,length(prc95(:, length(T_vector)))),'--','Color',[0.5 0.5 0.5],'LineWidth',2); %[output:37f1a114]
